import { Component, inject, OnInit, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { SlicePipe } from '@angular/common';
import { OrganizationService } from '../../core/services/organization.service';
import { OrgListDto, CreateOrgDto } from '../../core/models/organization.models';
import { PagedResult } from '../../core/models/common.models';

@Component({
  selector: 'app-organizations',
  standalone: true,
  imports: [FormsModule, SlicePipe],
  template: `
    <div class="page-header">
      <h1>Organizations</h1>
      <button class="btn btn-primary" (click)="showCreate = true">
        <span class="material-icons">add_business</span> New Organization
      </button>
    </div>

    <div class="card" style="padding:0;">
      @if (loading()) {
        <div class="loading-spinner"><div class="spinner"></div></div>
      } @else {
        <div class="table-wrap">
          <table class="data-table">
            <thead><tr><th>Name</th><th>Users</th><th>Status</th><th>Created</th></tr></thead>
            <tbody>
              @for (o of result()?.items; track o.id) {
                <tr>
                  <td>{{ o.name }}</td>
                  <td>{{ o.userCount }}</td>
                  <td><span class="badge" [class]="o.isActive ? 'badge-success' : 'badge-danger'">
                    {{ o.isActive ? 'Active' : 'Inactive' }}</span></td>
                  <td>{{ o.createdAt | slice:0:10 }}</td>
                </tr>
              } @empty {
                <tr><td colspan="4">
                  <div class="empty-state"><span class="material-icons">business</span><p>No organizations</p></div>
                </td></tr>
              }
            </tbody>
          </table>
        </div>
        <div class="pagination">
          <button [disabled]="page <= 1" (click)="changePage(-1)">‹</button>
          <span>{{ page }} / {{ result()?.totalPages ?? 1 }}</span>
          <button [disabled]="!result()?.hasNextPage" (click)="changePage(1)">›</button>
        </div>
      }
    </div>

    @if (showCreate) {
      <div class="modal-overlay" (click.self)="showCreate = false">
        <div class="modal">
          <div class="modal-header">
            <h2>New Organization</h2>
            <button class="close-btn" (click)="showCreate = false">✕</button>
          </div>
          <div class="modal-body">
            @if (error()) { <div class="alert alert-danger">{{ error() }}</div> }
            <div class="form-group"><label>Name</label>
              <input [(ngModel)]="form.name" placeholder="Acme Corp" /></div>
            <div class="form-group"><label>Description</label>
              <textarea [(ngModel)]="form.description" rows="3" placeholder="Optional description…"></textarea></div>
          </div>
          <div class="modal-footer">
            <button class="btn btn-secondary" (click)="showCreate = false">Cancel</button>
            <button class="btn btn-primary" (click)="create()" [disabled]="saving()">
              {{ saving() ? 'Creating…' : 'Create' }}
            </button>
          </div>
        </div>
      </div>
    }
  `,
  styleUrl: '../users/users.scss'
})
export class OrganizationsComponent implements OnInit {
  private svc = inject(OrganizationService);

  result  = signal<PagedResult<OrgListDto> | null>(null);
  loading = signal(false);
  saving  = signal(false);
  error   = signal('');
  showCreate = false;
  page = 1;
  form: CreateOrgDto = { name: '', description: '' };

  ngOnInit(): void { this.load(); }

  load(): void {
    this.loading.set(true);
    this.svc.getAll(this.page).subscribe({
      next: r => { this.result.set(r); this.loading.set(false); },
      error: () => this.loading.set(false)
    });
  }

  changePage(d: number): void { this.page += d; this.load(); }

  create(): void {
    this.error.set('');
    this.saving.set(true);
    this.svc.create(this.form).subscribe({
      next: () => { this.showCreate = false; this.saving.set(false); this.load(); },
      error: (e: Error) => { this.error.set(e.message); this.saving.set(false); }
    });
  }
}
